class Solution:
    def numsSameConsecDiff(self, n: int, k: int) -> List[int]:
        def dfs(num, n, k):
            if n == 0:
                result.append(num)
                return
            last_digit = num % 10
            if last_digit + k <= 9:
                dfs(num * 10 + last_digit + k, n - 1, k)
            if last_digit - k >= 0 and k != 0:
                dfs(num * 10 + last_digit - k, n - 1, k)

        result = []
        for i in range(1, 10):
            dfs(i, n - 1, k)
        return result
```
